.control-btn.main:hover &#123;  box-shadow: 0 5px 15px rgba(102, 126, 234, 0.5);&#125;
&#x2F;* 进度条 *&#x2F;.progress-container &#123;  margin-top: 8px;  position: relative;&#125;
.progress-bar &#123;  height: 4px;  background: #e8e8e8;  border-radius: 2px;  cursor: pointer;  position: relative;  user-select: none;  touch-action: none;&#125;
